schema.ddl:
CREATE TABLE insuranceclaim (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  businessId uuid NOT NULL,
  eventId uuid UNIQUE,
  correlationId uuid,
  status text NOT NULL,
  statusVersion integer NOT NULL,
  status text NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  updated_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX idx_insuranceclaim_businessId ON insuranceclaim (businessId);

CREATE INDEX idx_insuranceclaim_correlationId ON insuranceclaim (correlationId);

CREATE TABLE insuranceclaim_step_log (
  id bigserial PRIMARY KEY,
  insuranceclaim_id uuid NOT NULL,
  step text NOT NULL,
  status text NOT NULL,
  details jsonb,
  occurred_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX idx_insuranceclaim_step_log_ref ON insuranceclaim_step_log (insuranceclaim_id);

CREATE TABLE outbox (
  id bigserial PRIMARY KEY,
  aggregate_id uuid NOT NULL,
  event_type text NOT NULL,
  payload jsonb NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  published_at timestamptz
);

CREATE INDEX idx_outbox_unpublished ON outbox (id) WHERE published_at IS NULL;

CREATE TABLE inbox (
  provider_event_id text PRIMARY KEY,
  received_at timestamptz NOT NULL DEFAULT now(),
  payload jsonb NOT NULL,
  processed_at timestamptz
);

CREATE TABLE ledger (
  id bigserial PRIMARY KEY,
  account_id uuid NOT NULL,
  operation_id text NOT NULL UNIQUE,
  amount numeric(18,2) NOT NULL,
  kind text NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now()
);

CREATE INDEX idx_ledger_account ON ledger (account_id);
